---@type LFightIdleBaseAction
local LFightIdleBaseAction = LXImport(".LFightIdleBaseAction")

---@class LFightIdleScanAction:LFightIdleBaseAction
local LFightIdleScanAction = LxClass("LFightIdleScanAction",LFightIdleBaseAction)
-----------------------------------------------------------------

function LFightIdleScanAction:LFightIdleScanAction()
	self._action = LFightIdleConst.ACTION_SCAN

	self._nextScanTime = 0

	self._scanInterval = 0.2
end

-----------------------------------------------------------------
function LFightIdleScanAction:OnRun(time)
	if self._stopAction then
		return
	end
	if self._nextScanTime <= time then
		self:DoScan()
	end
end
-----------------------------------------------------------------
function LFightIdleScanAction:StartAction()
	if self._obj:SetStatus(LFightIdleConst.STATUS_IDLE) then
		self._obj:PlayIdleAni()
	end
	self._nextScanTime = -1
	self._stopAction = false
end
-----------------------------------------------------------------
function LFightIdleScanAction:DoScan()
	self._nextScanTime = self:GetTime() + self._scanInterval
	local objCtr =self:GetObjCtrl()
	local teamList = objCtr:GetOppositeTeamBySide(self._obj:GetSide())
	local bHave = false
	local bNoEnemy = true
	for k,v in ipairs(teamList) do
		if v:IsLive() then
			bHave = true
			bNoEnemy = false
			break
		end
		if bNoEnemy and not v:IsDestroy() and not v:IsDead() then
			bNoEnemy = false
		end
	end
	if bHave then
		self._ai:ChangeAction(LFightIdleConst.ACTION_ATK)
	elseif bNoEnemy then
		if self._obj:GetObjType() == LFightIdleConst.OBJ_HERO then
			self._manager:RefreshNextAreaEnemy()
		end
	end
end
-----------------------------------------------------------------


function LFightIdleScanAction:StopAction()
	self._stopAction = true
end

function LFightIdleScanAction:Destroy()

	LFightIdleBaseAction.Destroy(self)
end


return LFightIdleScanAction